mapper.select:
SELECT ci.car_id, ci.model_id, ci.plate_number, ci.vin_code, ci.vehicle_color, ci.current_mileage, ci.current_fuel, ci.daily_rent, ci.deposit_amount, ci.rental_count, ci.insurance_expiry, ci.status, ci.image_urls, ci.image_urls AS image, cm.model_name, cm.brand_name, cm.energy_type FROM car_info ci LEFT JOIN car_models cm ON ci.model_id = cm.model_id
AND (ci.plate_number LIKE CONCAT('%', #{query.keyword}, '%') OR ci.vin_code LIKE CONCAT('%', #{query.keyword}, '%'))
AND cm.brand_name = #{query.brand}
AND cm.energy_type = #{query.energyType}
AND ci.status = #{query.status}
ORDER BY ci.create_time DESC

SELECT ci.car_id, ci.model_id, ci.plate_number, ci.vin_code, ci.engine_no, ci.vehicle_color, ci.shop_id, ci.current_mileage, ci.current_fuel, ci.license_date, ci.insurance_expiry, ci.inspection_expiry, ci.daily_rent, ci.deposit_amount, ci.rental_count, ci.status, ci.image_urls,
cm.model_name, cm.series_name, cm.brand_name, cm.category, cm.energy_type, cm.gearbox_type, cm.drive_mode, cm.seat_count, cm.sunroof_type, cm.interior_color, cm.displacement, cm.fuel_grade, cm.emission_standard
FROM car_info ci LEFT JOIN car_models cm ON ci.model_id = cm.model_id WHERE ci.car_id = #{carId}
